using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.Save { public class StageClearSaveBinder:MonoBehaviour { [SerializeField] SaveManager saveManager; [SerializeField] GoalManager goalManager; [SerializeField] StageManager stageManager; [SerializeField] ScoreManager scoreManager; [SerializeField] MoveManager moveManager; bool saved; void Awake(){ saveManager??=FindAnyObjectByType<SaveManager>(); goalManager??=FindAnyObjectByType<GoalManager>(); stageManager??=FindAnyObjectByType<StageManager>(); scoreManager??=FindAnyObjectByType<ScoreManager>(); moveManager??=FindAnyObjectByType<MoveManager>(); } void OnEnable(){ if(goalManager!=null) goalManager.OnStageCleared+=Handle; } void OnDisable(){ if(goalManager!=null) goalManager.OnStageCleared-=Handle; } public void ResetSaveFlag()=>saved=false; void Handle(){ if(saved||saveManager==null||stageManager==null||scoreManager==null||moveManager==null) return; if(stageManager.StageNumber<1) return; saveManager.MarkStageClearedAndSave(stageManager.StageNumber,scoreManager.CurrentScore,moveManager.RemainingMoves); saved=true; } } }
